'use strict';

const {handleToken, hasAccessTokenHeader} = require('./access-token-handler');

module.exports = async function (req, res, next) {
  if (!hasAccessTokenHeader(req)) {
    return next();
  }

  try {
    await handleToken(req);
    next(); // proceed to service-to-approuter-middleware
  } catch (e) {
    const error = e.error ? e.error : e;
    const httpError = new Error(error.message);
    httpError.status = error.status;
    return next(httpError);
  }
};
